// From-scratch catalogue fills seasonal/fresh/quick slots and blank (unset) days; freezer & off keep their own pools.
function catCandidates(type){
  if(type==="quick")  return CATALOGUE.filter(c=>c.slot==="quick");
  if(type==="seasonal"||type==="fresh"||type==="") return CATALOGUE;
  return null;
}
/* ---------- shop quantities ---------- */
function isNum(s){ if(s===""||s==null) return false; const f=parseFloat(s); return isFinite(f) && String(s).trim()===String(f); }
function fmtNum(n){ return Number.isInteger(n)?String(n):String(Math.round(n*100)/100); }
function amtPiece(q,u){ if(!q) return ""; return u?`${q} ${u}`:`${q}`; }
function amtText(item){ if(item.amtEdited) return item.amt||""; const base=amtPiece(item.qty,item.unit); return item.more ? (base?`${base} + ${item.more}`:item.more) : base; }
// Unit handling for combining shop amounts.
const UNIT_QUALIFIERS = ["heaped","heaping","level","rounded","scant","generous"]; // dropped when comparing
const UNIT_PLURALS = { cloves:"clove", pieces:"piece", slices:"slice", knobs:"knob", heads:"head", bunches:"bunch", sticks:"stick", sprigs:"sprig", cans:"can", tins:"tin" };
const COUNT_UNITS = ["","clove","piece","slice","knob","head","bunch","stick","sprig","can","tin"]; // "" is a bare count
const ITEM_WEIGHT_G = { onion: 180 }; // average grams per whole item; lets weight and count combine
function normUnit(u){
  let s=(u||"").trim().toLowerCase();
  for(const q of UNIT_QUALIFIERS){ if(s.startsWith(q+" ")){ s=s.slice(q.length+1).trim(); break; } }
  if(UNIT_PLURALS[s]) s=UNIT_PLURALS[s];
  return s;
}
function isCountUnit(u){ return COUNT_UNITS.indexOf(normUnit(u))!==-1; }
function toGrams(q,u,wg){
  if(!isNum(q)) return null;
  const nu=normUnit(u);
  if(nu==="g") return parseFloat(q);
  if(nu==="kg") return parseFloat(q)*1000;
  if(isCountUnit(u)) return parseFloat(q)*wg; // whole items at the average weight
  return null; // tsp/tbsp/ml etc: no reliable conversion
}
// Combine a new recipe amount into an existing shop item.
function mergeAmt(qty,unit,more,nq,nu,name){
  more=more||""; unit=unit||"";
  const wg = ITEM_WEIGHT_G[(name||"").trim().toLowerCase()];
  // same unit once "heaped"/plurals are ignored: sum, show the plain base unit
  if(isNum(qty) && isNum(nq) && normUnit(unit)===normUnit(nu)) return { qty:fmtNum(parseFloat(qty)+parseFloat(nq)), unit:normUnit(unit), more };
  // a bare count ("7") and a named count ("7 clove") are the same thing: sum, keep the named unit
  if(isNum(qty) && isNum(nq) && isCountUnit(unit) && isCountUnit(nu) && (normUnit(unit)==="" || normUnit(nu)==="")) return { qty:fmtNum(parseFloat(qty)+parseFloat(nq)), unit: normUnit(unit)||normUnit(nu), more };
  // weight vs count for a known item (onion grams + whole onions): collapse to a whole-item count
  if(wg && !more){
    const g1=toGrams(qty,unit,wg), g2=toGrams(nq,nu,wg);
    if(g1!=null && g2!=null) return { qty:fmtNum(Math.max(1,Math.ceil((g1+g2)/wg))), unit:"", more:"" };
  }
  // anything genuinely different stays side by side, no conversion
  const piece=amtPiece(nq,nu);
  if(!piece) return { qty, unit, more };
  if(!qty && !more) return { qty:nq, unit:nu||"", more:"" };
  return { qty, unit, more: more?`${more} + ${piece}`:piece };
}

/* ---------- swipe-left-to-delete wrapper ---------- */
/* Uses `left` (not transform) for the offset: transform would create a stacking
   context that traps each row's store dropdown behind the rows below it. */
function SwipeRow({ onDelete, onStaple, children }){
  const [dx,setDx]=useState(0);
  const [removing,setRemoving]=useState(false);
  const [drag,setDrag]=useState(false);       // active horizontal drag (no transition while true)
  const sx=useRef(0), sy=useRef(0), active=useRef(false), decided=useRef(false), pid=useRef(null);
  const THRESH=78, LIMIT=150;
  const down=e=>{ if(removing) return; sx.current=e.clientX; sy.current=e.clientY; decided.current=false; active.current=false; pid.current=e.pointerId; };
  const move=e=>{
    if(pid.current==null||removing) return;
    const ddx=e.clientX-sx.current, ddy=e.clientY-sy.current;
    if(!decided.current){
      if(Math.abs(ddx)<6 && Math.abs(ddy)<6) return;            // too small to decide yet
      decided.current=true;
      if(Math.abs(ddx)>Math.abs(ddy)){ active.current=true; setDrag(true); try{ e.currentTarget.setPointerCapture(e.pointerId); }catch(_){} }
    }
    if(!active.current) return;                                   // vertical gesture: leave it to scroll
    if(e.cancelable) e.preventDefault();
    if(ddx<0) setDx(Math.max(ddx,-LIMIT));                        // left: pull to delete
    else setDx(onStaple ? Math.min(ddx,LIMIT) : Math.min(ddx*0.25,14)); // right: pull to staple (only where enabled)
  };
  const up=()=>{
    setDrag(false);
    if(active.current && dx<=-THRESH){ setRemoving(true); setDx(-520); setTimeout(()=>onDelete&&onDelete(),200); }
    else if(active.current && onStaple && dx>=THRESH){ setRemoving(true); setDx(520); setTimeout(()=>onStaple&&onStaple(),200); }
    else setDx(0);
    pid.current=null; active.current=false; decided.current=false;
  };
  const revealL=Math.min(1, Math.abs(Math.min(dx,0))/THRESH);    // left-swipe (delete) progress
  const revealR=Math.min(1, Math.max(dx,0)/THRESH);              // right-swipe (staple) progress
  const off = dx!==0 || removing;
  return (
    <div style={{ position:"relative", opacity:removing?0:1, transition:removing?"opacity 200ms ease":"none" }}>
      {off && dx<=0 && (
        <div style={{ position:"absolute", inset:0, borderRadius:12, background:"#A33A2A", display:"flex", alignItems:"center", justifyContent:"flex-end", paddingRight:18, gap:8, color:"#FBEFE6", zIndex:0 }}>
          <span style={{ fontSize:13, fontFamily:SANS, opacity:revealL }}>Already have it</span>
          <Trash2 size={18} style={{ opacity:Math.max(0.5,revealL) }} />
        </div>
      )}
      {off && dx>0 && onStaple && (
        <div style={{ position:"absolute", inset:0, borderRadius:12, background:"#7A5E32", display:"flex", alignItems:"center", justifyContent:"flex-start", paddingLeft:18, gap:8, color:"#FBEFE6", zIndex:0 }}>
          <Lock size={18} style={{ opacity:Math.max(0.5,revealR) }} />
          <span style={{ fontSize:13, fontFamily:SANS, opacity:revealR }}>Keep as staple</span>
        </div>
      )}
      <div onPointerDown={down} onPointerMove={move} onPointerUp={up} onPointerCancel={up}
           style={{ position:"relative", left:`${dx}px`, transition: drag?"none":"left 200ms ease", touchAction:"pan-y" }}>
        {children}
      </div>
    </div>
  );
}

