const SRC = { plan: "#EE6347", shop: "#E6B048", garden: "#6BBE74", freezer: "#5C93C8", kitchen: "#A99A8C", maint: "#C9A37A", pantry: "#D98E4A" };
const COND_TASKS = [];
const LATER_TASKS = [];

/* ---------- plan wizard ---------- */
const URGENT = [];
/* Catalogue-driven cook suggestions for a flagged use-up item.
   Pull the content words out of a freeform name, normalise spelling and plurals,
   then return every catalogue dish whose ingredients include the item, most-used first. */
const COOK_STOPWORDS = new Set(["a","an","the","of","some","few","couple","bit","half","quarter","leftover","leftovers","spare","opened","open","fresh","frozen","dried","plain","natural","greek","whole","light","reduced","fat","free","my","our","tub","tubs","jar","jars","packet","packets","pack","bag","bags","tin","tins","can","cans","box","boxes","punnet","punnets","carton","cartons","bottle","bottles","block","blocks","container","handful","piece","pieces","slice","slices","bunch","bunches"]);
const COOK_SPELL = { yoghurt:"yogurt", yoghurts:"yogurt", yogurts:"yogurt", chili:"chilli", chilis:"chilli", chillies:"chilli", tomatos:"tomato" }; // map AU/variant spellings to the catalogue's
function cookSingular(w){
  if(w.length<=3) return w;
  if(w.endsWith("ies")) return w.slice(0,-3)+"y";        // berries -> berry
  if(w.endsWith("oes")) return w.slice(0,-2);            // tomatoes -> tomato
  if(/(sh|ch|x|s|z)es$/.test(w)) return w.slice(0,-2);   // dishes -> dish
  if(w.endsWith("s") && !w.endsWith("ss") && !w.endsWith("us")) return w.slice(0,-1); // lemons -> lemon, keeps couscous/asparagus
  return w;
}
function cookNorm(w){ let s=w.toLowerCase().replace(/[^a-z]/g,""); if(COOK_SPELL[s]) s=COOK_SPELL[s]; s=cookSingular(s); if(COOK_SPELL[s]) s=COOK_SPELL[s]; return s; }
function cookContentWords(name){
  return (name||"").toLowerCase().split(/[^a-z]+/).filter(Boolean)
    .filter(w=>!COOK_STOPWORDS.has(w)).map(cookNorm).filter(Boolean).filter(w=>!COOK_STOPWORDS.has(w));
}
function cookIngTokens(i){ return new Set((i||"").toLowerCase().split(/[^a-z]+/).filter(Boolean).map(cookNorm).filter(Boolean)); }
// Use-up category map: a generic word expands to member ingredients for MATCHING only (never merges shop names).
const USEUP_CATEGORIES = {
  pasta: ["rigatoni","penne","spaghetti","linguine","bucatini","bigoli","orecchiette","tagliatelle","pappardelle","ditali","orzo","strozzapreti","tortiglioni","gnocchetti sardi","shell pasta","short pasta","cooked pasta","pasta"],
  greens: ["spinach","english spinach","silverbeet","silverbeet leaves","sauteed silverbeet","kale","cavolo nero","chicory","rocket","leafy greens","green leaves"],
};
// keyed by the normalised trigger word (e.g. "greens" -> "green") -> set of member names (lower-case)
const CAT_TRIGGER = (() => { const o={}; for(const k in USEUP_CATEGORIES){ o[cookNorm(k)] = new Set(USEUP_CATEGORIES[k].map(m=>m.toLowerCase())); } return o; })();
function useUpCatMembers(words){ const m=new Set(); for(const w of words){ const set=CAT_TRIGGER[w]; if(set) for(const x of set) m.add(x); } return m; }
function cookLiteralWords(words){ return words.filter(w=>!CAT_TRIGGER[w]); }
// Match an ingredient to a use-up item. Category members (pasta shapes, greens) match by exact name.
// Otherwise EVERY literal word of the use-up name must be present, so "white wine" no longer matches
// "white rice" and "tomato puree" no longer matches fresh tomatoes on a single shared word.
function ingMatchesUseUp(x, litWords, catMembers){ if(!x.i) return false; if(catMembers.has(x.i.toLowerCase())) return true; if(!litWords.length) return false; const toks=cookIngTokens(x.i); return litWords.every(w=>toks.has(w)); }
function dishUsesUseUp(dish, useUpName){ const words=cookContentWords(useUpName); if(!words.length) return false; const cm=useUpCatMembers(words); const lit=cookLiteralWords(words); return dish.ings.some(x=>ingMatchesUseUp(x,lit,cm)); }
function useUpUrgencyWeight(useBy, today0){ if(!useBy) return 1; const d=startOfDay(new Date(useBy)); if(isNaN(d)) return 1; const days=Math.round((d-today0)/86400000); if(days<=0) return 3; if(days<=7) return 2; return 1; }
function useUpScoreFor(dish, useUp, today0){ let sc=0; for(const u of (useUp||[])){ if(dishUsesUseUp(dish,u.name)) sc+=useUpUrgencyWeight(u.useBy,today0); } return sc; }
function dishSeasonalScore(dish, inSeasonProduce){ const seen=new Set(); for(const x of dish.ings){ if(x.sea&&x.p&&inSeasonProduce.has(x.p)) seen.add(x.p); } return seen.size; }
// Weighted random pick: use-up urgency dominates, seasonal nudges on seasonal days; falls back to plain random when no signal.
function chooseBiased(pool, exclude, biasSeasonal, useUp, today0, inSeasonProduce){
  const ex=(exclude||[]).filter(Boolean).map(s=>s.toLowerCase());
  let avail=pool.filter(c=>!ex.includes(c.name.toLowerCase())); if(!avail.length) avail=pool; if(!avail.length) return null;
  // Weighted random over the whole available pool: use-up urgency, and in-season produce on seasonal
  // days, raise a dish's odds, but every dish keeps a real base chance so suggestions stay varied.
  const scored=avail.map(c=>{
    const uu=useUpScoreFor(c,useUp,today0);
    const se=biasSeasonal?dishSeasonalScore(c,inSeasonProduce):0;
    return { c, w: 1 + uu*3 + se*1.5 };
  });
  const total=scored.reduce((s,o)=>s+o.w, 0);
  let r=Math.random()*total;
  for(const o of scored){ r-=o.w; if(r<=0) return o.c; }
  return scored[scored.length-1].c;
}
// Rough comparable scale so most-used sorts first across mixed units. Volume -> ml; grams kept on the same axis; whole items get a nominal. Order is approximate by design.
function cookAmount(q,u){
  const n=parseFloat(q); const v=isFinite(n)?n:1; const unit=(u||"").trim().toLowerCase();
  const ML={ tsp:5, tbsp:15, cup:250, fl_oz:30, ml:1, l:1000, litre:1000, pinch:1 };
  if(ML[unit]!==undefined) return v*ML[unit];
  if(unit==="kg") return v*1000;
  if(unit==="g")  return v;
  return v*100; // counts, cloves, pieces, whole items
}
function cookLabel(q,u,name){ const hasQ=!(q===""||q==null); const amt=!hasQ?"":(u?`${q} ${u}`:`${q}`); return amt?`${name}, ${amt}`.trim():(name||""); }
function cookSuggestionsFor(name){
  const words=cookContentWords(name);
  if(!words.length) return [];
  const cm=useUpCatMembers(words);
  const lit=cookLiteralWords(words);
  const out=[];
  for(const c of CATALOGUE){
    let best=null;
    for(const x of c.ings){
      if(!ingMatchesUseUp(x,lit,cm)) continue;
      const amt=cookAmount(x.q,x.u); if(!best||amt>best.amt) best={amt,q:x.q,u:x.u,i:x.i};
    }
    if(best) out.push({ id:c.id, name:c.name, ref:c.ref, label:cookLabel(best.q,best.u,best.i), amt:best.amt, cookMin:c.cookMin, serves:c.serves });
  }
  out.sort((a,b)=> b.amt-a.amt || a.cookMin-b.cookMin);
  return out;
}
