/* ---------- utilities ---------- */
function rgba(hex, a) { const h = hex.replace("#", ""); return `rgba(${parseInt(h.slice(0,2),16)},${parseInt(h.slice(2,4),16)},${parseInt(h.slice(4,6),16)},${a})`; }
function sameDay(a, b) { return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate(); }
function startOfDay(d) { const x=new Date(d); x.setHours(0,0,0,0); return x; }
function addDays(d, n) { const x=new Date(d); x.setDate(x.getDate()+n); return x; }
function fmtDate(d) { return d.toLocaleDateString("en-AU", { weekday:"short", day:"numeric", month:"short" }); }
// First on-or-after `from` that lands on weekday `dow`.
function nextWeekday(from, dow) { const d=startOfDay(from); const diff=(dow - d.getDay() + 7) % 7; return addDays(d, diff); }
// Given a current due date, roll forward by the frequency, snapping to the same weekday.
function rollDue(currentDue, freq, dow) { const base=addDays(currentDue, FREQS[freq].days - 3); return nextWeekday(base, dow); }
function pickFrom(list, exclude) { const ex=exclude.filter(Boolean).map(s=>s.toLowerCase()); const avail=list.filter(it=>!ex.includes(it.name.toLowerCase())); const pool=avail.length?avail:list; return pool[Math.floor(Math.random()*pool.length)]; }
function mondayOf(date) { const d=new Date(date); const dow=d.getDay(); d.setDate(d.getDate()+(dow===0?-6:1-dow)); d.setHours(0,0,0,0); return d; }
function buildWeek(offset) {
  const base=mondayOf(new Date()); base.setDate(base.getDate()+offset*7);
  const names=["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]; const today=new Date();
  const defs = DEFAULTS_BLANK; // all weeks start blank; only Friday defaults to Night Off
  return names.map((name,i)=>{ const d=new Date(base); d.setDate(base.getDate()+i); return { id:name, weekday:name, date:d, dateLabel:d.toLocaleDateString("en-AU",{day:"numeric",month:"short"}), isToday:sameDay(d,today), type:defs[name], dish:null, suggested:false }; });
}

/* ---------- persistence layer (standalone phone build uses localStorage) ---------- */
const STORE_PREFIX = "de1:";
function usePersistentState(key, initial, revive){
  const [v,setV]=useState(()=>{
    try{ const raw=localStorage.getItem(STORE_PREFIX+key); if(raw!=null){ const parsed=JSON.parse(raw); return revive?revive(parsed):parsed; } }catch(e){}
    return typeof initial==="function"?initial():initial;
  });
  useEffect(()=>{ try{ localStorage.setItem(STORE_PREFIX+key, JSON.stringify(v)); }catch(e){} },[key,v]);
  return [v,setV];
}
function weekKeyOf(weekDays){ return startOfDay(weekDays[0].date).toISOString().slice(0,10); }
function loadPlan(){ try{ const raw=localStorage.getItem(STORE_PREFIX+"plan"); return raw?JSON.parse(raw):{}; }catch(e){ return {}; } }

