  const changeWeek = delta  => { setWeekOffset(o=>Math.min(3,Math.max(0,o+delta))); setMenuFor(null); setEditFor(null); setWeekAdded(null); };
  const switchView = v      => { setMenuFor(null); setEditFor(null); setStorePickerFor(null); setIngPreviewFor(null); setSeasonalPickFor(null); setFavePickFor(null); setPickIngFor(null); setMoveFor(null); setView(v); };
  const reserveFreezer = (frozenId) => {
    if(!frozenId) return;
    setFreezer(fz=>fz.map(f=>f.id===frozenId?{...f, qty:Math.max(0,(f.qty||0)-1)}:f));
  };
  const returnFreezer = (dish) => {
    if(!dish || !dish.frozenId) return;
    setFreezer(fz=>{
      if(fz.some(f=>f.id===dish.frozenId)) return fz.map(f=>f.id===dish.frozenId?{...f, qty:(f.qty||0)+1}:f);
      const m=dish.frozenMeta||{};
      return [...fz, { id:dish.frozenId, name:dish.name, serves:m.serves||4, qty:1, loc:m.loc||FREEZER_LOCATIONS[0], frozen:m.frozen?new Date(m.frozen):new Date() }];
    });
  };
  const passedDay = (day) => !!day && startOfDay(day.date) < today0;
  // Keep the freezer in step when a day's dish changes: a freezer meal leaving the plan before its
  // day passes goes back to storage; a freezer meal placed reserves one out of storage.
  const reconcileFreezer = (o,id,newDish) => {
    const day=weeks[o].find(d=>d.id===id);
    const old=day&&day.dish;
    const oldId=old&&old.frozenId;
    const newId=newDish&&newDish.frozenId;
    if(oldId && oldId!==newId && !passedDay(day)) returnFreezer(old);
    if(newId && newId!==oldId) reserveFreezer(newId);
  };
  const suggest    = (o,id) => {
    const day=weeks[o].find(d=>d.id===id);
    if(day.type==="freezer"){
      const avail=freezer.filter(f=>f.qty>0);
      if(!avail.length) return;   // nothing actually in the freezer to suggest
      const c=pickFrom(avail,[...history, day.dish?day.dish.name:""]);
      const dish={name:c.name, ref:"", frozen:true, frozenId:c.id, frozenMeta:{serves:c.serves, loc:c.loc, frozen:c.frozen}};
      reconcileFreezer(o,id,dish);
      patch(o,id,{ dish, suggested:true });
      return;
    }
    const catTypes=["faves","quick","seasonal","fresh",""];
    if(catTypes.includes(day.type)){
      let pool;
      if(day.type==="faves"){ pool=CATALOGUE.filter(c=>favesSet.has(c.id) && !favesHiddenSet.has(c.id)); if(!pool.length) pool=CATALOGUE; }
      else if(day.type==="quick"){ pool=CATALOGUE.filter(c=>c.slot==="quick"); }
      else if(day.type==="seasonal"){ pool=CATALOGUE.filter(c=>dishSeasonalScore(c,inSeasonProduce)>0); if(!pool.length) pool=CATALOGUE; } // seasonal slot actually draws on what's in season now
      else { pool=CATALOGUE; }
      const memKey=`${o}:${id}`;
      const recent=suggestMemory.current[memKey]||[];
      const exclude=[...history, day.dish?day.dish.name:"", ...recent];
      let c=chooseBiased(pool, exclude, day.type==="seasonal", useUp, today0, inSeasonProduce);
      if(c && day.dish && c.name===day.dish.name && pool.length>1){ c=chooseBiased(pool, [...exclude, c.name], day.type==="seasonal", useUp, today0, inSeasonProduce) || c; }
      if(c){
        suggestMemory.current[memKey]=[c.name, ...recent.filter(n=>n!==c.name)].slice(0, Math.max(1, Math.min(8, pool.length-1)));
        const dish={name:c.name, ref:c.ref, catId:c.id}; reconcileFreezer(o,id,dish); patch(o,id,{ dish, suggested:true });
      }
    } else {
      const dish={...pickFrom(POOLS[day.type],[...history, day.dish?day.dish.name:""])};
      reconcileFreezer(o,id,dish);
      patch(o,id,{ dish, suggested:true });
    }
  };
  const pickCatalogue = (o,id,c) => {
    const dish={name:c.name, ref:c.ref, catId:c.id};
    reconcileFreezer(o,id,dish);
    const day=weeks[o].find(d=>d.id===id);
    const extra = (day && !day.type)
      ? { type: favesSet.has(c.id) ? "faves" : dishSeasonalScore(c,inSeasonProduce)>0 ? "seasonal" : c.slot==="quick" ? "quick" : "fresh" }
      : {};
    patch(o,id,{ dish, suggested:false, ...extra });
    setHistory(h=>[c.name,...h.filter(x=>x.toLowerCase()!==c.name.toLowerCase())].slice(0,12));
    setCatPickFor(null); setCatQuery(""); setCatAdded(null);
  };
  const pickFreezer = (o,id,f) => {
    const dish={name:f.name, ref:"", frozen:true, frozenId:f.id, frozenMeta:{serves:f.serves, loc:f.loc, frozen:f.frozen}};
    reconcileFreezer(o,id,dish);
    patch(o,id,{ dish, suggested:false });
    setHistory(h=>[f.name,...h.filter(x=>x.toLowerCase()!==f.name.toLowerCase())].slice(0,12));
    setCatPickFor(null); setCatQuery(""); setCatAdded(null);
  };
  const openCatalogue = id => { setEditFor(null); setMenuFor(null); setCatAdded(null); setCatQuery(""); setCatAll(false); setIngPreviewFor(null); setCatPickFor(id); };
  const browsePoolFor = (type) => {
    if(type==="quick"){ const q=CATALOGUE.filter(c=>c.slot==="quick"); return q.length?q:CATALOGUE; }
    if(type==="faves"){ const q=CATALOGUE.filter(c=>favesSet.has(c.id) && !favesHiddenSet.has(c.id)); return q.length?q:CATALOGUE; }
    if(type==="seasonal"){ const q=CATALOGUE.filter(c=>dishSeasonalScore(c,inSeasonProduce)>0); return q.length?q:CATALOGUE; }
    return CATALOGUE;
  };
  // Ingredients that would go on the shop list: catalogue non-staples, or a custom dish's typed-in list.
  const dishShopIngs = (dish) => {
    if(!dish) return [];
    if(dish.catId && CAT_BY_ID[dish.catId]) return CAT_BY_ID[dish.catId].ings.filter(x=>!x.s && x.i && !staplesSet.has(x.i.toLowerCase())).map(x=>({i:x.i,q:x.q,u:x.u}));
    if(dish.ings) return dish.ings.filter(x=>x.i && !staplesSet.has(x.i.toLowerCase())).map(x=>({i:x.i,q:x.q||"",u:x.u||""}));
    return [];
  };
